module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

    reg [31:0] product;
    reg [4:0] count;
    reg [15:0] multiplicand, multiplier;
    reg done_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            product <= 0;
            count <= 0;
            multiplicand <= 0;
            multiplier <= 0;
            done_reg <= 0;
        end else if (start) begin
            multiplicand <= ain;
            multiplier <= bin;
            count <= 16;
            product <= 0;
            done_reg <= 0;
        end else if (count > 0) begin
            if (multiplier[0]) begin
                product <= product + (multiplicand << (16 - count));
            end
            multiplier <= multiplier >> 1;
            count <= count - 1;
            if (count == 1) begin
                done_reg <= 1;
            end
        end else begin
            done_reg <= 0;
        end
    end

    assign yout = product;
    assign done = done_reg;

endmodule
